import React, { useState, useEffect, useRef } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import toast from 'react-hot-toast';
import { useAuth } from '../context/AuthContext';
import Navbar from '../components/Navbar';
import PostCard from '../components/PostCard';

export default function ProfilePage() {
  const { username } = useParams();
  const { user: currentUser, updateUser } = useAuth();
  const navigate = useNavigate();

  const [profile, setProfile] = useState(null);
  const [posts, setPosts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [following, setFollowing] = useState(false);
  const [activeTab, setActiveTab] = useState('posts'); // posts | saved
  const [showEditModal, setShowEditModal] = useState(false);
  const [selectedPost, setSelectedPost] = useState(null);

  useEffect(() => {
    setLoading(true);
    setProfile(null);
    setPosts([]);
    fetchProfile();
  }, [username]);

  const fetchProfile = async () => {
    try {
      const [profileRes, postsRes] = await Promise.all([
        axios.get(`/api/users/${username}/profile`),
        axios.get(`/api/users/${username}/posts`),
      ]);
      setProfile(profileRes.data);
      setFollowing(profileRes.data.is_following);
      setPosts(postsRes.data);
    } catch (err) {
      if (err.response?.status === 404) navigate('/');
      else toast.error('Failed to load profile');
    } finally { setLoading(false); }
  };

  const toggleFollow = async () => {
    const prev = following;
    setFollowing(!prev);
    setProfile(p => ({ ...p, followers_count: prev ? p.followers_count - 1 : p.followers_count + 1 }));
    try {
      await axios.post(`/api/users/${profile.id}/follow`);
      toast.success(!prev ? `Following ${profile.username}` : `Unfollowed ${profile.username}`);
    } catch {
      setFollowing(prev);
      setProfile(p => ({ ...p, followers_count: prev ? p.followers_count + 1 : p.followers_count - 1 }));
    }
  };

  const handleNewPost = (post) => setPosts(prev => [post, ...prev]);

  const handlePostDeleted = (postId) => {
    setPosts(prev => prev.filter(p => p.id !== postId));
    setSelectedPost(null);
    setProfile(p => ({ ...p, posts_count: p.posts_count - 1 }));
  };

  const handleProfileUpdated = (updated) => {
    setProfile(p => ({ ...p, ...updated }));
    updateUser(updated);
    setShowEditModal(false);
    toast.success('Profile updated!');
  };

  if (loading) return (
    <div style={{ background: '#fafafa', minHeight: '100vh' }}>
      <Navbar onNewPost={handleNewPost} />
      <div style={{ marginLeft: 72, display: 'flex', justifyContent: 'center', paddingTop: 40 }}>
        <ProfileSkeleton />
      </div>
    </div>
  );

  if (!profile) return null;

  const avatarUrl = profile.avatar ? `http://localhost:5000${profile.avatar}` : null;
  const initials = (profile.username || 'U')[0].toUpperCase();
  const isOwn = profile.is_own;

  return (
    <div style={{ background: '#fafafa', minHeight: '100vh' }}>
      <Navbar onNewPost={handleNewPost} />

      <div style={{ marginLeft: 72, maxWidth: 935, margin: '0 auto', paddingLeft: 72, paddingTop: 40, paddingBottom: 40 }}>

        {/* Profile Header */}
        <div style={S.header}>
          {/* Avatar */}
          <div style={S.avatarWrap}>
            {avatarUrl
              ? <img src={avatarUrl} alt="" style={S.avatar} />
              : <div style={S.avatarPh}>{initials}</div>
            }
          </div>

          {/* Info */}
          <div style={S.info}>
            {/* Username row */}
            <div style={S.usernameRow}>
              <h2 style={S.username}>{profile.username}</h2>
              {isOwn ? (
                <button style={S.editBtn} onClick={() => setShowEditModal(true)}>Edit profile</button>
              ) : (
                <div style={{ display: 'flex', gap: 8 }}>
                  <button
                    onClick={toggleFollow}
                    style={{ ...S.followBtn, ...(following ? S.followingBtn : {}) }}
                  >
                    {following ? 'Following' : 'Follow'}
                  </button>
                  <button style={S.messageBtn}>Message</button>
                </div>
              )}
            </div>

            {/* Stats */}
            <div style={S.stats}>
              <div style={S.stat}>
                <span style={S.statNum}>{Number(profile.posts_count).toLocaleString()}</span>
                <span style={S.statLabel}>posts</span>
              </div>
              <div style={S.stat}>
                <span style={S.statNum}>{Number(profile.followers_count).toLocaleString()}</span>
                <span style={S.statLabel}>followers</span>
              </div>
              <div style={S.stat}>
                <span style={S.statNum}>{Number(profile.following_count).toLocaleString()}</span>
                <span style={S.statLabel}>following</span>
              </div>
            </div>

            {/* Bio */}
            <div style={S.bio}>
              {profile.full_name && <div style={{ fontWeight: 600, fontSize: 14 }}>{profile.full_name}</div>}
              {profile.bio && <div style={{ fontSize: 14, whiteSpace: 'pre-wrap', marginTop: 4 }}>{profile.bio}</div>}
              {!profile.bio && isOwn && (
                <button onClick={() => setShowEditModal(true)} style={{ color: '#0095f6', fontSize: 14, background: 'none', border: 'none', cursor: 'pointer', padding: 0 }}>
                  + Add bio
                </button>
              )}
            </div>
          </div>
        </div>

        {/* Tabs */}
        <div style={S.tabs}>
          <button
            style={{ ...S.tab, ...(activeTab === 'posts' ? S.activeTab : {}) }}
            onClick={() => setActiveTab('posts')}
          >
            <svg viewBox="0 0 24 24" width="12" height="12" fill="currentColor" style={{ marginRight: 6 }}>
              <rect x="3" y="3" width="7" height="7"/><rect x="14" y="3" width="7" height="7"/>
              <rect x="3" y="14" width="7" height="7"/><rect x="14" y="14" width="7" height="7"/>
            </svg>
            POSTS
          </button>
          {isOwn && (
            <button
              style={{ ...S.tab, ...(activeTab === 'saved' ? S.activeTab : {}) }}
              onClick={() => setActiveTab('saved')}
            >
              <svg viewBox="0 0 24 24" width="12" height="12" fill="none" stroke="currentColor" strokeWidth="2" style={{ marginRight: 6 }}>
                <path d="M19 21l-7-5-7 5V5a2 2 0 012-2h10a2 2 0 012 2z"/>
              </svg>
              SAVED
            </button>
          )}
        </div>

        {/* Posts Grid */}
        {activeTab === 'posts' && (
          posts.length === 0 ? (
            <div style={S.emptyPosts}>
              <svg viewBox="0 0 24 24" width="48" height="48" fill="none" stroke="#dbdbdb" strokeWidth="1">
                <rect x="3" y="3" width="18" height="18" rx="2"/>
                <circle cx="8.5" cy="8.5" r="1.5"/><polyline points="21 15 16 10 5 21"/>
              </svg>
              <h3 style={{ marginTop: 16, fontSize: 18, color: '#262626' }}>
                {isOwn ? 'Share your first photo' : 'No posts yet'}
              </h3>
              {isOwn && <p style={{ color: '#8e8e8e', marginTop: 8, fontSize: 14 }}>Click + in the sidebar to create a post.</p>}
            </div>
          ) : (
            <div style={S.grid}>
              {posts.map(post => (
                <div key={post.id} style={S.gridItem} onClick={() => setSelectedPost(post)}>
                  {post.image_url
                    ? <img src={`http://localhost:5000${post.image_url}`} alt="" style={S.gridImg} />
                    : <div style={S.gridNoImg}>
                        <p style={{ padding: 12, fontSize: 13, color: '#fff', textAlign: 'center' }}>{post.caption}</p>
                      </div>
                  }
                  {/* Hover overlay */}
                  <div style={S.gridOverlay}>
                    <span style={S.gridStat}>
                      <svg viewBox="0 0 24 24" width="18" height="18" fill="white"><path d="M20.84 4.61a5.5 5.5 0 00-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 00-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 000-7.78z"/></svg>
                      {Number(post.likes_count).toLocaleString()}
                    </span>
                    <span style={S.gridStat}>
                      <svg viewBox="0 0 24 24" width="18" height="18" fill="white"><path d="M21 15a2 2 0 01-2 2H7l-4 4V5a2 2 0 012-2h14a2 2 0 012 2z"/></svg>
                      {Number(post.comments_count).toLocaleString()}
                    </span>
                  </div>
                </div>
              ))}
            </div>
          )
        )}

        {activeTab === 'saved' && (
          <div style={S.emptyPosts}>
            <svg viewBox="0 0 24 24" width="48" height="48" fill="none" stroke="#dbdbdb" strokeWidth="1">
              <path d="M19 21l-7-5-7 5V5a2 2 0 012-2h10a2 2 0 012 2z"/>
            </svg>
            <h3 style={{ marginTop: 16, fontSize: 18, color: '#262626' }}>Saved</h3>
            <p style={{ color: '#8e8e8e', marginTop: 8, fontSize: 14 }}>Save photos and videos that you want to see again.</p>
          </div>
        )}
      </div>

      {/* Post Detail Modal */}
      {selectedPost && (
        <PostDetailModal
          post={selectedPost}
          currentUser={currentUser}
          onClose={() => setSelectedPost(null)}
          onDeleted={handlePostDeleted}
          onUpdated={(updated) => {
            setPosts(prev => prev.map(p => p.id === updated.id ? { ...p, ...updated } : p));
            setSelectedPost(prev => ({ ...prev, ...updated }));
          }}
        />
      )}

      {/* Edit Profile Modal */}
      {showEditModal && (
        <EditProfileModal
          profile={profile}
          onClose={() => setShowEditModal(false)}
          onSaved={handleProfileUpdated}
        />
      )}
    </div>
  );
}

// ── POST DETAIL MODAL ─────────────────────────────────────────
function PostDetailModal({ post, currentUser, onClose, onDeleted, onUpdated }) {
  const [comments, setComments] = useState([]);
  const [commentText, setCommentText] = useState('');
  const [liked, setLiked] = useState(post.user_liked > 0);
  const [likesCount, setLikesCount] = useState(Number(post.likes_count));
  const [showDots, setShowDots] = useState(false);
  const [editingCaption, setEditingCaption] = useState(false);
  const [captionText, setCaptionText] = useState(post.caption || '');
  const isOwn = currentUser?.id === post.user_id;

  useEffect(() => {
    axios.get(`/api/posts/${post.id}/comments`).then(r => setComments(r.data)).catch(() => {});
  }, [post.id]);

  const toggleLike = async () => {
    setLiked(p => !p);
    setLikesCount(c => liked ? c - 1 : c + 1);
    await axios.post(`/api/posts/${post.id}/like`).catch(() => {});
  };

  const addComment = async e => {
    e.preventDefault();
    if (!commentText.trim()) return;
    try {
      const { data } = await axios.post(`/api/posts/${post.id}/comments`, { text: commentText });
      setComments(p => [...p, data]);
      setCommentText('');
    } catch { toast.error('Failed to comment'); }
  };

  const deletePost = async () => {
    if (!window.confirm('Delete this post?')) return;
    try {
      await axios.delete(`/api/posts/${post.id}`);
      toast.success('Post deleted');
      onDeleted(post.id);
    } catch { toast.error('Failed to delete'); }
  };

  const saveCaption = async () => {
    try {
      await axios.put(`/api/posts/${post.id}/caption`, { caption: captionText });
      onUpdated({ id: post.id, caption: captionText });
      setEditingCaption(false);
      toast.success('Caption updated!');
    } catch { toast.error('Failed to update'); }
  };

  const avatarUrl = post.avatar ? `http://localhost:5000${post.avatar}` : null;
  const initials = (post.username || 'U')[0].toUpperCase();
  const postImageUrl = post.image_url ? `http://localhost:5000${post.image_url}` : null;

  function timeAgo(dateStr) {
    const diff = (Date.now() - new Date(dateStr)) / 1000;
    if (diff < 60) return 'just now';
    if (diff < 3600) return `${Math.floor(diff/60)}m ago`;
    if (diff < 86400) return `${Math.floor(diff/3600)}h ago`;
    return new Date(dateStr).toLocaleDateString('en-US', { month: 'long', day: 'numeric' });
  }

  return (
    <div style={MS.overlay} onClick={e => e.target === e.currentTarget && onClose()}>
      <div style={MS.modal}>
        {/* Left — image */}
        {postImageUrl && (
          <div style={MS.imagePane}>
            <img src={postImageUrl} alt="post" style={MS.image} />
          </div>
        )}

        {/* Right — details */}
        <div style={MS.detailPane}>
          {/* Header */}
          <div style={MS.detailHeader}>
            <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
              {avatarUrl
                ? <img src={avatarUrl} alt="" style={MS.avatar} />
                : <div style={MS.avatarPh}>{initials}</div>
              }
              <span style={{ fontWeight: 600, fontSize: 14 }}>{post.username}</span>
            </div>
            <div style={{ position: 'relative' }}>
              <button onClick={() => setShowDots(p => !p)} style={{ background: 'none', border: 'none', cursor: 'pointer', fontSize: 20, padding: '2px 8px', letterSpacing: 2 }}>···</button>
              {showDots && (
                <>
                  <div style={{ position: 'fixed', inset: 0, zIndex: 998 }} onClick={() => setShowDots(false)} />
                  <div style={MS.dotsMenu}>
                    {isOwn ? (
                      <>
                        <button style={MS.dotsItem} onClick={() => { setEditingCaption(true); setShowDots(false); }}>Edit caption</button>
                        <div style={{ height: 1, background: '#efefef' }} />
                        <button style={{ ...MS.dotsItem, color: '#ed4956', fontWeight: 700 }} onClick={deletePost}>Delete</button>
                        <div style={{ height: 1, background: '#efefef' }} />
                        <button style={MS.dotsItem} onClick={() => setShowDots(false)}>Cancel</button>
                      </>
                    ) : (
                      <>
                        <button style={{ ...MS.dotsItem, color: '#ed4956', fontWeight: 700 }} onClick={() => { toast('Reported'); setShowDots(false); }}>Report</button>
                        <div style={{ height: 1, background: '#efefef' }} />
                        <button style={MS.dotsItem} onClick={() => setShowDots(false)}>Cancel</button>
                      </>
                    )}
                  </div>
                </>
              )}
            </div>
          </div>

          {/* Caption + comments */}
          <div style={MS.commentsList}>
            {/* Caption */}
            {(post.caption || editingCaption) && (
              <div style={{ display: 'flex', gap: 10, marginBottom: 12 }}>
                {avatarUrl
                  ? <img src={avatarUrl} alt="" style={MS.commentAvatar} />
                  : <div style={MS.commentAvatarPh}>{initials}</div>
                }
                <div style={{ flex: 1 }}>
                  {editingCaption ? (
                    <div>
                      <textarea
                        value={captionText}
                        onChange={e => setCaptionText(e.target.value)}
                        style={{ width: '100%', border: '1px solid #dbdbdb', borderRadius: 4, padding: 8, fontSize: 14, resize: 'none', outline: 'none' }}
                        rows={3}
                        autoFocus
                      />
                      <div style={{ display: 'flex', gap: 8, marginTop: 4 }}>
                        <button onClick={saveCaption} style={{ color: '#0095f6', fontWeight: 700, fontSize: 13, background: 'none', border: 'none', cursor: 'pointer' }}>Save</button>
                        <button onClick={() => { setEditingCaption(false); setCaptionText(post.caption || ''); }} style={{ color: '#8e8e8e', fontSize: 13, background: 'none', border: 'none', cursor: 'pointer' }}>Cancel</button>
                      </div>
                    </div>
                  ) : (
                    <span style={{ fontSize: 14 }}><span style={{ fontWeight: 600 }}>{post.username}</span> {captionText}</span>
                  )}
                </div>
              </div>
            )}

            {/* Comments */}
            {comments.map(c => {
              const cAvatar = c.avatar ? `http://localhost:5000${c.avatar}` : null;
              const cInitials = (c.username || 'U')[0].toUpperCase();
              return (
                <div key={c.id} style={{ display: 'flex', gap: 10, marginBottom: 10 }}>
                  {cAvatar
                    ? <img src={cAvatar} alt="" style={MS.commentAvatar} />
                    : <div style={MS.commentAvatarPh}>{cInitials}</div>
                  }
                  <div>
                    <span style={{ fontSize: 14 }}><span style={{ fontWeight: 600 }}>{c.username}</span> {c.text}</span>
                    <div style={{ color: '#8e8e8e', fontSize: 11, marginTop: 2 }}>{timeAgo(c.created_at)}</div>
                  </div>
                </div>
              );
            })}
          </div>

          {/* Actions */}
          <div style={MS.actions}>
            <div style={{ display: 'flex', gap: 14, marginBottom: 8 }}>
              <button onClick={toggleLike} style={{ background: 'none', border: 'none', cursor: 'pointer', padding: 0 }}>
                <svg viewBox="0 0 24 24" width="24" height="24" fill={liked ? '#ed4956' : 'none'} stroke={liked ? '#ed4956' : '#262626'} strokeWidth="2">
                  <path d="M20.84 4.61a5.5 5.5 0 00-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 00-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 000-7.78z"/>
                </svg>
              </button>
              <button style={{ background: 'none', border: 'none', cursor: 'pointer', padding: 0 }}>
                <svg viewBox="0 0 24 24" width="24" height="24" fill="none" stroke="#262626" strokeWidth="2">
                  <path d="M21 15a2 2 0 01-2 2H7l-4 4V5a2 2 0 012-2h14a2 2 0 012 2z"/>
                </svg>
              </button>
            </div>
            <div style={{ fontWeight: 600, fontSize: 14, marginBottom: 4 }}>{likesCount.toLocaleString()} likes</div>
            <div style={{ color: '#8e8e8e', fontSize: 11 }}>{timeAgo(post.created_at).toUpperCase()}</div>
          </div>

          {/* Add comment */}
          <form onSubmit={addComment} style={MS.commentForm}>
            <input
              value={commentText}
              onChange={e => setCommentText(e.target.value)}
              placeholder="Add a comment..."
              style={MS.commentInput}
            />
            {commentText && (
              <button type="submit" style={{ color: '#0095f6', fontWeight: 700, fontSize: 14, background: 'none', border: 'none', cursor: 'pointer' }}>Post</button>
            )}
          </form>
        </div>
      </div>

      {/* Close button */}
      <button onClick={onClose} style={{ position: 'fixed', top: 16, right: 16, background: 'none', border: 'none', cursor: 'pointer', color: '#fff', fontSize: 32, lineHeight: 1, zIndex: 2001 }}>×</button>
    </div>
  );
}

// ── EDIT PROFILE MODAL ────────────────────────────────────────
function EditProfileModal({ profile, onClose, onSaved }) {
  const [form, setForm] = useState({
    full_name: profile.full_name || '',
    bio: profile.bio || '',
    username: profile.username || '',
  });
  const [avatarPreview, setAvatarPreview] = useState(profile.avatar ? `http://localhost:5000${profile.avatar}` : null);
  const [avatarFile, setAvatarFile] = useState(null);
  const [saving, setSaving] = useState(false);
  const fileRef = useRef();

  const handleFile = e => {
    const file = e.target.files[0];
    if (!file) return;
    setAvatarFile(file);
    setAvatarPreview(URL.createObjectURL(file));
  };

  const save = async () => {
    setSaving(true);
    try {
      const fd = new FormData();
      fd.append('full_name', form.full_name);
      fd.append('bio', form.bio);
      if (avatarFile) fd.append('avatar', avatarFile);
      const { data } = await axios.put('/api/users/profile', fd, {
        headers: { 'Content-Type': 'multipart/form-data' }
      });
      onSaved(data);
    } catch { toast.error('Failed to save profile'); }
    finally { setSaving(false); }
  };

  const initials = (profile.username || 'U')[0].toUpperCase();

  return (
    <div style={ES.overlay} onClick={e => e.target === e.currentTarget && onClose()}>
      <div style={ES.modal}>
        <div style={ES.header}>
          <span style={{ fontWeight: 700, fontSize: 16 }}>Edit profile</span>
          <button onClick={onClose} style={{ fontSize: 22, background: 'none', border: 'none', cursor: 'pointer', color: '#262626' }}>×</button>
        </div>

        {/* Avatar picker */}
        <div style={ES.avatarSection} onClick={() => fileRef.current.click()}>
          {avatarPreview
            ? <img src={avatarPreview} alt="" style={ES.avatar} />
            : <div style={ES.avatarPh}>{initials}</div>
          }
          <div style={{ marginLeft: 16 }}>
            <div style={{ fontWeight: 600, fontSize: 14 }}>{profile.username}</div>
            <button type="button" style={{ color: '#0095f6', fontWeight: 700, fontSize: 14, background: 'none', border: 'none', cursor: 'pointer', padding: 0, marginTop: 4 }}>
              Change profile photo
            </button>
          </div>
          <input ref={fileRef} type="file" accept="image/*" style={{ display: 'none' }} onChange={handleFile} />
        </div>

        {/* Fields */}
        <div style={ES.fields}>
          <div style={ES.field}>
            <label style={ES.label}>Full Name</label>
            <input style={ES.input} value={form.full_name} onChange={e => setForm(p => ({ ...p, full_name: e.target.value }))} placeholder="Full name" />
          </div>
          <div style={ES.field}>
            <label style={ES.label}>Username</label>
            <input style={{ ...ES.input, color: '#8e8e8e' }} value={form.username} disabled placeholder="Username" />
            <span style={{ fontSize: 12, color: '#8e8e8e', marginTop: 4, display: 'block' }}>Username cannot be changed.</span>
          </div>
          <div style={ES.field}>
            <label style={ES.label}>Bio</label>
            <textarea
              style={{ ...ES.input, resize: 'none', height: 80 }}
              value={form.bio}
              onChange={e => setForm(p => ({ ...p, bio: e.target.value }))}
              placeholder="Write something about yourself..."
              maxLength={150}
            />
            <span style={{ fontSize: 12, color: '#8e8e8e', textAlign: 'right', display: 'block' }}>{form.bio.length}/150</span>
          </div>
        </div>

        <div style={{ padding: '16px 24px', borderTop: '1px solid #dbdbdb', display: 'flex', justifyContent: 'flex-end', gap: 8 }}>
          <button onClick={onClose} style={{ padding: '8px 16px', borderRadius: 8, background: '#efefef', border: 'none', cursor: 'pointer', fontWeight: 600, fontSize: 14 }}>Cancel</button>
          <button onClick={save} style={{ padding: '8px 20px', borderRadius: 8, background: '#0095f6', color: '#fff', border: 'none', cursor: 'pointer', fontWeight: 700, fontSize: 14, opacity: saving ? 0.7 : 1 }} disabled={saving}>
            {saving ? 'Saving...' : 'Save'}
          </button>
        </div>
      </div>
    </div>
  );
}

